INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07110', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列句子中的「適」字，與李商隱〈樂遊原〉「向晚意不適，驅車登古原。夕陽無 限好，只是近黃昏」詩中的「適」字意義相同的是：', '["此時魯仲連「適」遊趙", "子「適」衛，冉有僕", "百骸九竅，無一得「適」", "君子之於天下也，無「適」也，無莫也，義之與比"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07111', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列各組「」中的字義，兩兩相同的是：', '["吾離群而「索」居，亦已久矣/路漫漫其修遠兮，吾將上下而求「索」", "修己以安百姓，堯舜「其」猶病諸/與爾三矢，爾「其」無忘乃父之志", "「卒」然臨之而不驚，無故加之而不怒/李廣軍極簡易，然虜「卒」犯之，無以 禁也", "天命之謂性，「率」性之謂道/將「率」三軍，北定中原"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07112', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列關於詩人風格的說明，何者正確？', '["陶淵明文字綺麗華美，合乎魏晉時代的審美標準，故受時人所重", "柳宗元詩風雄深雅健，深峭詭誕，屬奇險派詩人", "李商隱詩風「質而實綺，而實腴」，樸實而意味深長", "白居易詩多反映現實社會，主張「文章合為時而著，歌詩合為事而作」 美學修養是知識份子追求知識的起點，也同樣是終極關懷。我們共同希望，這個社 會上的知識份子，能找回美學修養，它不僅是對音樂美術的喜愛，同時要把美學修養變 成情感性的、對待人的態度，也就是一種關照與尊重，它同時具備了情感的敏銳度，和 理性的節制，我覺得情感的豐沛是很重要的，如果沒有了情，理性只是乾枯的僵化教條 而已，要知道什麼是愛、關心、牽掛、眷戀，然後理性發生作用，把情感處理得好，處 理得當，生命才圓滿。（摘錄自蔣勳：〈知識份子的美學修養〉）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07113', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列敘述何者符合作者所表達的想法？', '["推廣美學修養是知識份子被期待的社會責任", "美學素養能讓人的理性與感性發展協調，豐實生命", "音樂美術有潛移默化的影響，是美學教育的首要目標", "知識份子應運用自己的美學修養，發揮終極關懷的功能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07114', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「西子能令轉嫁吳，會稽知爾啄姑蘇。跡高塵外功成處，一葉翩翩在五湖」，上引 詩文，所稱述的對象是：', '["夫差", "西施", "范蠡", "句踐"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07115', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '錢大昕〈奕喻〉：「吾能知人之失而不能見吾之失；吾能指人之小失而不能見吾之 大失」，意涵與下列選項何者相同？', '["目中無人", "目不見睫", "目不識丁", "目不暇給"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07116', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '蘇軾〈琴詩〉：「若言琴上有琴聲，放在匣中何不鳴？若言聲在指頭上，何不於君 指上聽」，蘇軾寫作這首詩想要表達的主旨是：', '["說明琴的材質決定了琴聲的優劣", "藉匣中不鳴之琴表達自己的不遇", "希望會彈琴的友人為他彈奏一曲", "借琴事來說明言外之旨，絃外之音"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07117', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「碧玉妝成一樹高，萬條垂下綠絲。不知細葉誰裁出？二月春風似剪刀」，是歌 詠那一種植物？', '["椰樹", "芭蕉", "楊柳", "蔦蘿 鏡子，不僅讓我們看清自己的形貌，而且想起形貌背後的靈魂和自我。 我們忍不住想對鏡裝扮。只是有些人想裝扮他的形貌，而有些人想裝扮他的靈魂。 不管是裝扮自己的形貌或靈魂，我們都因鏡子而成為一名演員。 現在終於輪到你在塵世這個舞臺登場演出的時刻。 如果你想裝扮自己的形貌，你可能需要更大的鏡子、更多的燈光；但如果你想裝扮 自己的靈魂，我勸你最好將眼光從手中的鏡子挪開，到其他地方去尋找你需要的鏡子。 「以銅為鏡」不如「以人為鏡」。 在這齣即將由你擔綱演出的人生之戲裡，你要演出什麼角色，雖然由你自己決定； 劇本也有賴你自己去編寫：但如果你想要有精彩而漂亮的演出，也許你應該先參考一下 前人的戲碼。（王溢嘉〈鏡裡朱顏〉） 請依上文回答第16題至第17題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07118', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「鏡子，不僅讓我們看清自己的形貌，而且想起形貌背後的靈魂和自我」，下列選 項何者與本文無涉？', '["正衣冠", "知興替", "明自我", "探心靈"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07119', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「以銅為鏡」不如「以人為鏡」之意義，下列選項何者錯誤？', '["銅鏡勝於人鏡", "人鏡貴於銅鏡", "銅鏡僅能修飾形貌", "人鏡可以修飾得失 諸子十家，其可觀者九家而已。‥‥‥《易》曰：「天下同歸而殊塗，一致而百慮。」 今異家者各推所長，窮知究慮，以明其指，雖有蔽短，合其要歸，亦《六經》之支與流 裔。使其人遭明王聖主，得其所折中，皆股肱之材已。仲尼有言：「禮失而求諸野。」 方今去聖久遠，道術缺廢，無所更索，彼九家者，不猶愈於野乎？若能修六藝之術，而 觀此九家之言，舍短取長，則可以通萬方之略矣。（《漢書．藝文志．諸子略序》） 請依上文回答第18題至第19題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
